1	use std::path::PathBuf;
2	use std::sync::Arc;
3	
4	use portable_pty::{native_pty_system, CommandBuilder, MasterPty, PtySize};
5	use tokio::sync::{broadcast, mpsc, RwLock};
6	
7	use atn_core::agent::{AgentConfig, AgentId, AgentState};
8	use atn_core::error::{AtnError, Result};
9	use atn_core::event::{InputEvent, OutputSignal};
10	
11	use crate::reader::spawn_reader_task;
12	use crate::transcript::TranscriptWriter;
13	use crate::writer::spawn_writer_task;
14	
15	const PTY_ROWS: u16 = 40;
16	const PTY_COLS: u16 = 120;
17	const OUTPUT_CHANNEL_CAPACITY: usize = 256;
18	const INPUT_CHANNEL_CAPACITY: usize = 64;
19	
20	/// A managed PTY session for one agent.
21	pub struct PtySession {
22	    agent_id: AgentId,
23	    child: Box<dyn portable_pty::Child + Send>,
24	    input_tx: mpsc::Sender<InputEvent>,
25	    output_tx: broadcast::Sender<OutputSignal>,
26	    state: Arc<RwLock<AgentState>>,
27	    _master: Box<dyn MasterPty + Send>,
28	    _reader_handle: tokio::task::JoinHandle<()>,
29	    _writer_handle: tokio::task::JoinHandle<()>,
30	    _transcript_handle: Option<tokio::task::JoinHandle<()>>,
31	}
32	
33	impl PtySession {
34	    /// Spawn a new PTY session for the given agent configuration.
35	    ///
36	    /// If `log_dir` is provided, transcript and event logs are written to
37	    /// `{log_dir}/{agent_id}/`.
38	    pub async fn spawn(config: &AgentConfig, log_dir: Option<PathBuf>) -> Result<Self> {
39	        let pty_system = native_pty_system();
40	
41	        let pair = pty_system
42	            .openpty(PtySize {
43	                rows: PTY_ROWS,
44	                cols: PTY_COLS,
45	                pixel_width: 0,
46	                pixel_height: 0,
47	            })
48	            .map_err(|e| AtnError::Pty(e.to_string()))?;
49	
50	        let mut cmd = CommandBuilder::new("bash");
51	        cmd.cwd(&config.repo_path);
52	
53	        let child = pair
54	            .slave
55	            .spawn_command(cmd)
56	            .map_err(|e| AtnError::Pty(e.to_string()))?;
57	
58	        // Drop slave — we only interact via the master side.
59	        drop(pair.slave);
60	
61	        let reader = pair
62	            .master
63	            .try_clone_reader()
64	            .map_err(|e| AtnError::Pty(e.to_string()))?;
65	
66	        let writer = pair
67	            .master
68	            .take_writer()
69	            .map_err(|e| AtnError::Pty(e.to_string()))?;
70	
71	        let (output_tx, _) = broadcast::channel(OUTPUT_CHANNEL_CAPACITY);
72	        let (input_tx, input_rx) = mpsc::channel(INPUT_CHANNEL_CAPACITY);
73	        let state = Arc::new(RwLock::new(AgentState::Starting));
74	
75	        let reader_handle = spawn_reader_task(reader, output_tx.clone());
76	        let writer_handle = spawn_writer_task(writer, input_rx);
77	
78	        // Optionally start transcript logging.
79	        let transcript_handle = if let Some(dir) = log_dir {
80	            let agent_dir = dir.join(&config.id.0);
81	            let tw = TranscriptWriter::new(&agent_dir)?;
82	            let rx = output_tx.subscribe();
83	            Some(tw.spawn(rx))
84	        } else {
85	            None
86	        };
87	
88	        // Inject setup commands.
89	        let setup_tx = input_tx.clone();
90	        let setup_commands = config.setup_commands.clone();
91	        let launch = config.launch_command.clone();
92	        let state_clone = state.clone();
93	        tokio::spawn(async move {
94	            // Set a known prompt for the outer shell.
95	            let _ = setup_tx
96	                .send(InputEvent::CoordinatorCommand {
97	                    command: r#"export PS1="__ATN_READY__> ""#.to_string(),
98	                })
99	                .await;
100	
101	            for cmd in &setup_commands {
102	                let _ = setup_tx
103	                    .send(InputEvent::CoordinatorCommand {
104	                        command: cmd.clone(),
105	                    })
106	                    .await;
107	            }
108	
109	            if !launch.is_empty() {
110	                let _ = setup_tx
111	                    .send(InputEvent::CoordinatorCommand {
112	                        command: launch,
113	                    })
114	                    .await;
115	            }
116	
117	            let mut s = state_clone.write().await;
118	            *s = AgentState::Running;
119	        });
120	
121	        Ok(Self {
122	            agent_id: config.id.clone(),
123	            child,
124	            input_tx,
125	            output_tx,
126	            state,
127	            _master: pair.master,
128	            _reader_handle: reader_handle,
129	            _writer_handle: writer_handle,
130	            _transcript_handle: transcript_handle,
131	        })
132	    }
133	
134	    /// The agent ID for this session.
135	    pub fn agent_id(&self) -> &AgentId {
136	        &self.agent_id
137	    }
138	
139	    /// Get a clone of the input sender for this session.
140	    pub fn input_sender(&self) -> mpsc::Sender<InputEvent> {
141	        self.input_tx.clone()
142	    }
143	
144	    /// Send an input event to the agent's PTY.
145	    pub async fn send_input(&self, event: InputEvent) -> Result<()> {
146	        self.input_tx
147	            .send(event)
148	            .await
149	            .map_err(|e| AtnError::Channel(e.to_string()))
150	    }
151	
152	    /// Send Ctrl-C (0x03) to the agent's PTY.
153	    pub async fn send_ctrl_c(&self) -> Result<()> {
154	        self.send_input(InputEvent::RawBytes {
155	            bytes: vec![0x03],
156	        })
157	        .await
158	    }
159	
160	    /// Get a new receiver for the agent's output stream.
161	    pub fn output_receiver(&self) -> broadcast::Receiver<OutputSignal> {
162	        self.output_tx.subscribe()
163	    }
164	
165	    /// Get a clone of the agent's state handle.
166	    pub fn state(&self) -> Arc<RwLock<AgentState>> {
167	        self.state.clone()
168	    }
169	
170	    /// Shut down the agent session.
171	    ///
172	    /// Sends Ctrl-C twice (1s apart), waits for exit, then kills if needed.
173	    pub async fn shutdown(&mut self) -> Result<()> {
174	        // First Ctrl-C
175	        let _ = self.send_ctrl_c().await;
176	        tokio::time::sleep(std::time::Duration::from_secs(1)).await;
177	
178	        // Second Ctrl-C
179	        let _ = self.send_ctrl_c().await;
180	        tokio::time::sleep(std::time::Duration::from_secs(2)).await;
181	
182	        // Try to kill the child process.
183	        self.child
184	            .kill()
