fn send_ctrl_c(agent_id: &str) {
    use gloo_net::http::Request;
    let url = format!("/api/agents/{}/ctrl-c", agent_id);
    wasm_bindgen_futures::spawn_local(async move {
        let _ = Request::post(&url).send().await;
    });
}

